import { Link } from "react-router-dom";

function Home() {
  return (
    <div className="home">
      <h1>Master DSA Step by Step</h1>
      <p>Your structured roadmap to crack tech interviews.</p>

      <Link to="/sheet" className="btn">
        Start Practice
      </Link>
    </div>
  );
}

export default Home;
